import '../lib/merge_policy.dart';
import '../lib/sync_engine.dart';
import '../lib/vector_clock.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

SyncRecord record({
  required String id,
  required bool deleted,
  required int modifiedAt,
  required String device,
  required Map<String, int> clock,
}) =>
    SyncRecord(
      id: id,
      value: deleted ? '' : 'body',
      deleted: deleted,
      modifiedAt: modifiedAt,
      deviceId: device,
      clock: clock,
    );

void main() {
  final extensionOrder = compareClocks(
    {'phone': 1},
    {'phone': 1, 'tablet': 1},
  );
  check(extensionOrder == ClockOrder.before, 'new actor component was ignored');

  final active = record(
    id: 'feedback-delete',
    deleted: false,
    modifiedAt: 50,
    device: 'alpha',
    clock: {'phone': 2},
  );
  final tombstone = record(
    id: 'feedback-delete',
    deleted: true,
    modifiedAt: 50,
    device: 'zulu',
    clock: {'tablet': 3},
  );
  check(resolveRecord(active, tombstone).deleted, 'tombstone lost tie break');

  final engine = SyncEngine([
    record(
      id: 'feedback-join',
      deleted: false,
      modifiedAt: 20,
      device: 'phone',
      clock: {'phone': 2},
    ),
  ]);
  engine.applyRemote(
    record(
      id: 'feedback-join',
      deleted: false,
      modifiedAt: 30,
      device: 'tablet',
      clock: {'tablet': 1},
    ),
  );
  final joined = engine.records['feedback-join']!.clock;
  check(
    joined['phone'] == 2 && joined['tablet'] == 1,
    'resolved clock did not join both histories',
  );
}
